{"content": "#!/usr/bin/env bash\nset -euo pipefail\n\n# Kill leftovers\npkill -f \"nats-server\" 2>/dev/null || true\npkill -f \"counter-uas-director\" 2>/dev/null || true\nsleep 2\n\n# Start NATS\nnats-server -c /Users/vincent/Work/BOD-CUAS/demo/golden/nats.conf &\nsleep 2\n\n# Start counter-uas-director\nRUST_LOG=debug /Users/vincent/Work/furia-core/target/release/counter-uas-director &\nDIRECTOR_PID=$!\nsleep 3\n\n# Publish an observation\npython3 << 'PYEOF'\nimport json, socket, time\nsock = socket.create_connection(('127.0.0.1', 4222), timeout=10)\n_ = sock.recv(4096)\nsock.sendall(b'CONNECT {\\\"verbose\\\":false}\\r\\nPING\\r\\n')\n_ = sock.recv(4096)\n\nnow_ms = int(time.time() * 1000)\npayload = json.dumps({\n    \"observation\": {\n        \"kind\": \"non_cooperative_target\",\n        \"observed_at_ms\": now_ms,\n        \"position\": {\"latitude_e7\": 448500000, \"longitude_e7\": -7000000, \"altitude_msl_mm\": 50000},\n        \"velocity_ned_mm_s\": [1200, -300, 0],\n        \"horizontal_uncertainty_mm\": 2000,\n        \"vertical_uncertainty_mm\": 1000,\n        \"cooperative\": False,\n        \"authorized\": None,\n        \"identity\": None,\n        \"provenance\": {\n            \"category\": 15, \"edition\": \"1.0\", \"profile\": None,\n            \"sac\": 1, \"sic\": 2, \"source_track_id\": 4660, \"pair_id\": None,\n            \"received_at_ms\": now_ms,\n            \"raw_record_sha256\": [0] * 32,\n        },\n    }\n})\nsock.sendall(f\"PUB surveillance.observation {len(payload)}\\r\\n\".encode() + payload.encode() + b\"\\r\\n\")\nsock.sendall(b\"PING\\r\\n\")\n_ = sock.recv(4096)\nprint(\"Published observation\")\nsock.close()\nPYEOF\n\nsleep 2\n\n# Publish operator authorization\npython3 << 'PYEOF'\nimport json, socket, time\nsock = socket.create_connection(('127.0.0.1', 4222), timeout=10)\n_ = sock.recv(4096)\nsock.sendall(b'CONNECT {\\\"verbose\\\":false}\\r\\nPING\\r\\n')\n_ = sock.recv(4096)\n\npayload = json.dumps({\n    \"action\": \"intercept\", \"track_id\": \"4660\",\n    \"operator\": \"demo-operator\",\n    \"authorization_id\": \"bod-demo-auth-4660\",\n    \"authorized\": True,\n})\nsock.sendall(f\"PUB operator.action.authorized {len(payload)}\\r\\n\".encode() + payload.encode() + b\"\\r\\n\")\nsock.sendall(b\"PING\\r\\n\")\n_ = sock.recv(4096)\nprint(\"Published authorization\")\nsock.close()\nPYEOF\n\nsleep 3\n\n# Check director log for delegation\nif kill -0 $DIRECTOR_PID 2>/dev/null; then\n    echo \"Director still running\"\nelse\n    echo \"Director exited\"\nfi\n\n# Kill director\nkill $DIRECTOR_PID 2>/dev/null || true\nwait $DIRECTOR_PID 2>/dev/null || true\n\npkill -f \"nats-server\" 2>/dev/null || true\necho \"Done\"", "file_path": "/Users/vincent/Work/BOD-CUAS/demo/golden/test_observation.sh"}